    """
    Reads the per-user ``people_config`` table. Falls back to the file on error.

    Returns:
        ``{"people": [...]}`` shape matching :func:`_load_people_config`.
    """
    try:
        from utils.db_store import _coerce_uuid  # type: ignore[attr-defined]
        from db.database import get_cursor

        uid = _coerce_uuid(user_id)
        if uid is None:
            return _load_people_config()
        with get_cursor(commit=False) as cur:
            cur.execute(
                """
                SELECT name, email, role, priority_weight
                FROM people_config
                WHERE user_id = %s
                ORDER BY priority_weight DESC, name ASC;
                """,
                (uid,),
            )
