    """Resolves the owning user_id from a task id when in DB mode."""
    if not settings.USE_DB_STORAGE:
        return fallback
    try:
        from utils.db_store import db_lookup_user_for_task
        return db_lookup_user_for_task(task_id) or fallback
    except Exception as e:
        print(f"[ERROR][M5] _resolve_user_id failed for task {task_id}: {e}")
        return fallback

